window.__QUIZ_DATA__=[{"id":"theory>Geography>1998>1>a","subject":"Geography","year":"1998","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Describe population distribution in India under the following headings:  Factors responsible","images":[],"marking_scheme":"-Warm monsoon climate and abundant rainfall  -Early settlement, early maturity and high fecundity rate  -Has one of the highest population clusters in the world  -Presence of fertile alluvial soil which supports a lot of rice cultivation  -Low population concentration in mountainous areas, e.g the Deccan region  -Density is as high as 100 persons per km2  -Recent development it industry, low population in arid regions, e,g the Thar Desert  -Commercial activities  -Development of good network of transport","marks":"8","difficulty":"2"},{"id":"theory>Geography>1998>1>b","subject":"Geography","year":"1998","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Describe population distribution in India under the following headings:  Advantages","images":[],"marking_scheme":"-Revenue accruing to government from income tax  -Large pool of labour  -Military advantage  -High demand for goods and services  -Export of manpower to earn foreign exchange","marks":"8","difficulty":"2"},{"id":"theory>Geography>1998>1>c","subject":"Geography","year":"1998","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Describe population distribution in India under the following headings:    Problems","images":[],"marking_scheme":"-High cost of living  -Unemployment and under-development  -Food shortage  -Inadequate hour  -High rate of crime  -Occurrence of diseases  -Political and social unrest  -Slum development","marks":"4","difficulty":"2"},{"id":"theory>Geography>1998>2>a","subject":"Geography","year":"1998","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Identify, with examples, any four ways in which urban settlements differ from one another","images":[],"marking_scheme":"-Plan layout (structure)  -Outlook (cleanliness, beauty, quality and services)  -Site (physical location)  -Situation (location in relation to other areas)  -Size  -Function","marks":"10","difficulty":"2"},{"id":"theory>Geography>1998>2>b","subject":"Geography","year":"1998","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"In which four ways are rural settlements dependent on urban settlements?","images":[],"marking_scheme":"-Economic services like banking, insurance, etc  -Factory produced goods  -Employment  -Sale of industrial raw materials  -Educational services  -Health services (especially secondary and tertiary healthcare)  -Administrative services  -Justice and security  -Purchase of agricultural products.","marks":"10","difficulty":"2"},{"id":"theory>Geography>1998>3>a","subject":"Geography","year":"1998","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"In what four ways is air transportation different from water transportation?","images":[],"marking_scheme":"-Air transportation is faster than water transportation  -Water transport is more suitable for carrying bulky goods than air transport  -Air transport can be used to reach the most remote, most distant and most inhospitable places on earth (in terms of climate) water transport is limited to water bodies only  -water transport is interrupted by hazards of rapids, falls and fogs while air transport is disrupted by visibility alone  -Air transport costs more than water transportation in the hauling of goods and services  -Air transport is used for movement of human beings, perishable and precious goods ti water transport.","marks":"8","difficulty":"2"},{"id":"theory>Geography>1998>3>b","subject":"Geography","year":"1998","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Highlight three major contributions of transportation to national development","images":[],"marking_scheme":"-Enhances communication  -Promotes trade  -Generates employment  -Generates revenue  -Income for workers  -Promotes tour  -Enhances military movement","marks":"8","difficulty":"2"},{"id":"theory>Geography>1998>3>c","subject":"Geography","year":"1998","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"State any three problems of water transportation in Tropical Africa","images":[],"marking_scheme":"-Capital intensive dredging of harbours and waterways  -Seasonal fluctuation of water level  -Presence of water-weeds  -Presence of rapids and falls  -Pilfering of goods at seaports  -Sand spits and sand bars  -Inadequate goy to carry at some seaports.","marks":"4","difficulty":"2"},{"id":"theory>Geography>1998>4>a","subject":"Geography","year":"1998","type":"Theory","sub_label":"a","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Highlight any three characteristics of manufacturing industries in Tropical Africa","images":[],"marking_scheme":"-Depend on imported machinery  -Lab intensive  -Mainly small scale industries  -Dominated by foreign multinational corporations  -Mainly import substituting  -Produce mainly consumer goods  -Concentrated in towns","marks":"8","difficulty":"2"},{"id":"theory>Geography>1998>4>b","subject":"Geography","year":"1998","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"State four ways by which manufacturing industries contribute to the economic development of Tropical Africa","images":[],"marking_scheme":"-Provision of goods  -Income to workers  -Revenue to the government  -Employment generation  -Provision of infrastructure  -Conservation foreign exchange  -Diversification of economy","marks":"8","difficulty":"2"},{"id":"theory>Geography>1998>4>c","subject":"Geography","year":"1998","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Outline four problems facing industrial development in the region","images":[],"marking_scheme":"-Inadequate capital  -Political instability  -Poor management  -Inadequate power supply  -Inadequate skilled manpower  -Competition posed by foreign goods  -Poor transport and communication facilities","marks":"4","difficulty":"2"},{"id":"theory>Geography>1998>5>a","subject":"Geography","year":"1998","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Describe five factors responsible for the low volumes of trade between Nigeria and the other African countries","images":[],"marking_scheme":"-Preference for goods from advanced countries  -Poor transport links  -Similarity in products  -Low level of technology  -Trade restrictions  -Existence of regional trade unions  -Ties with former colonial masters","marks":"10","difficulty":"3"},{"id":"theory>Geography>1998>5>b","subject":"Geography","year":"1998","type":"Theory","sub_label":"b","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Suggest five ways of increasing the volume of trade between Nigeria and the other countries in Africa","images":[],"marking_scheme":"-Construction of transcontinental transport network  -Protection from competition  -Encouraging specialisation in production  -Improving savings capacity  -Formation of an African Economic Community  -Patronizing locally made goods by all countries in Africa  -Improving technology","marks":"10","difficulty":"3"},{"id":"theory>Geography>1998>6>a","subject":"Geography","year":"1998","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Differentiate between the practice of agriculture in the forest and savanna regions of Nigeria under the following headings:  Favourable factors","images":[],"marking_scheme":"-Land areas in the savanna are more suitable for mechanized farming than in the forest region  -There is all year-round rainfall for perennial agriculture in the forest region while seasonal rainfall in the savanna supports seasonal cropping  -Rainfall amount in the forest regions supports trees and root crops, while in the savanna, it supports cereals and legumes  -Animal farming practised more in the savanna  -Enough sunshine available in the savanna for fruit ripening while little is required in the forest region  -Two planting seasons in the forest region but one in the savanna region  -Deep well-drained forest soil are suitable for tree and root crops while the shallow but well-drained savana soils favour cereal and legumes","marks":"8","difficulty":"3"},{"id":"theory>Geography>1998>6>b","subject":"Geography","year":"1998","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Differentiate between the practice of agriculture in the sorest and savanna regions of Nigeria under the following headings:  Products","images":[],"marking_scheme":"-Food crops of the savanna include maize, rice, millet sorghum, groundnut, cow-peas, etc, while food crops of the forest region include yams, cassava, cocoyams, kolanuts, coconuts, and various other types of fruits,  -More fruits in the forest  -Savanna is more favourable for large scale livestock farming than the forest region  -More vegetables in the savanna  -Cash crops in the savanna include cotton, ginger, groundnuts, while in the forest region they include oil palm, rubber, cocoa and cashew","marks":"8","difficulty":"3"},{"id":"theory>Geography>1998>6>c","subject":"Geography","year":"1998","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Differentiate between the practice of agriculture in the sorest and savanna regions of Nigeria under the following headings:  Economic importance","images":[],"marking_scheme":"-Income to farmers  -Revenue to government  -Industrial raw materials  -Provision of food  -Foreign exchange earner  -Employment generation","marks":"4","difficulty":"3"},{"id":"theory>Geography>1998>7>a","subject":"Geography","year":"1998","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Draw a map of Nigeria and on it, show the  - Rivers Kaduna, Cross and Ogun  - Source area of each river in (a) (i) above","images":["data:image/png;base64,"],"marking_scheme":"","marks":"8","difficulty":"2"},{"id":"theory>Geography>1998>7>b","subject":"Geography","year":"1998","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Describe any four characteristics of rivers in Nigeria","images":[],"marking_scheme":"-Occurrence of rapids and waterfalls  -Seasonality  -Most are short and swift flowing  -Shallow depths  -Presence of water-weeds  -Deposition along river beds  -Silting of the mouths","marks":"8","difficulty":"2"},{"id":"theory>Geography>1998>7>c","subject":"Geography","year":"1998","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : RESOURCES","question":"In what four ways are rivers useful to the economy of Nigeria?","images":[],"marking_scheme":"-Irrigation  -Transportation  -For fishing  -HEP generation  -Tourism and recreation  -Domestic and municipal uses  -Industrial use","marks":"4","difficulty":"2"},{"id":"theory>Geography>1998>8>a","subject":"Geography","year":"1998","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"State five ways in which highlands promote economic development in the North Central Highlands","images":[],"marking_scheme":"-Sources of solid minerals (e.g, tin in Jos Plateau)  -Promotion of tourism  -Sources of rivers  -High plains suitable for crop farming  -Provision of pasture for grazing  -Presence of waterfalls for HEP generation  -Used for mounting communication masts  -Rocks and gravels for construction","marks":"10","difficulty":"3"},{"id":"theory>Geography>1998>8>b","subject":"Geography","year":"1998","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"What five characteristics of highlands hinder the development of the region?","images":[],"marking_scheme":"-Transportation difficulty  -Remoteness of some highlands makes them inaccessible  -Steep nature of the slopes leads to rapid soil erosion  -Ruggedness of highlands limits agricultural production  -Highlands are vast, thus making integrated development difficult  -Rain shadow effect on the leeward side limits development","marks":"10","difficulty":"2"},{"id":"theory>Geography>1998>9>a","subject":"Geography","year":"1998","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : RESOURCES","question":"Draw a map of Nigeria and on it, locate and name  - three solid-mineral-mining towns and the solid mineral foi in each  - three refinery town","images":["data:image/png;base64,"],"marking_scheme":"","marks":"8","difficulty":"3"},{"id":"theory>Geography>1998>9>b","subject":"Geography","year":"1998","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Outline any four contributions of solid minerals to the economy of Nigeria","images":[],"marking_scheme":"-Revenue to the government  -Income for workers  -Generate employment  -Source of foreign exchange  -Raw materials in industries  -Facilitates infrastructural development  -Facilitate growth of towns","marks":"8","difficulty":"2"},{"id":"theory>Geography>1998>9>c","subject":"Geography","year":"1998","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"State any three problems which face the mining of solid minerals in Nigeria","images":[],"marking_scheme":"-Low level of technology  -Inadequate skilled manpower  -Inadequate capital  -Inadequate infrastructure  -Competition from alternative sources  -Illegal transactions/illegal mining/bunkering  -Exhaustion or depletion of deposits","marks":"4","difficulty":"2"},{"id":"theory>Geography>1998>10>a","subject":"Geography","year":"1998","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : RESOURCES","question":"Outline any three factors which favour lumbering in Nigeria","images":[],"marking_scheme":"-High rainfall  -Presence of forests with many species of  timber  -High demand for wood as fuel  -Presence of roads for transportation  -Presence of rivers (Niger and Ethiope) for easy evacuation of timber  -High demand for timber within and outside Nigeria","marks":"8","difficulty":"2"},{"id":"theory>Geography>1998>10>b","subject":"Geography","year":"1998","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Highlight any four contributions of lumbering to economy of Nigeria","images":[],"marking_scheme":"-Wood for fuel  -Source of employment  -Income for workers  -Raw materials for home and industries  -Facilitates infrastructural development  -Timber exported for foreign exchange  -Source of revenue for government  -For construction","marks":"8","difficulty":"2"},{"id":"theory>Geography>1998>10>c","subject":"Geography","year":"1998","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"State any five problems facing lumbering in Nigeria","images":[],"marking_scheme":"-Transportation difficulties resulting from seasonal roads  -Inadequate capital  -Trees are closely planted and so difficult to fell  -Low level of technology  -Trees with buttress roots make their felling costly  -Difficulty of searching for desired type among many species of trees  -Transportation difficulties resulting from seasonal roads  -Activities of illegal lumbermen  -Logging difficulties resulting from dense undergrowth.","marks":"4","difficulty":"2"},{"id":"theory>Geography>1998>11>a","subject":"Geography","year":"1998","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Name any four ocean currents along the coast of Africa","images":[],"marking_scheme":"-Guinea  -Canary  -Somali (N-E of Somalia)  -Benguela  -Agulhas or Mozambique","marks":"10","difficulty":"1"},{"id":"theory>Geography>1998>11>b","subject":"Geography","year":"1998","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Highlight the effects of any two different types of currents on the climate of Africa","images":[],"marking_scheme":"Guinea Current (Warm):  -Warm current  -Dense cloud cover  -Land ans sea breeze  -Heavy rainfall especially along the coast  -Off the coast of WestAfrica  -High humidity  -Onshore winds  -Low temperature range  -Forest in the areas near the coast  -Thunder and lightening are prevalent    (ii) Canary Current (Cold):  -Low humidity  -Cooling effect of ocean reduces temperature   -Little or no rainfall  -Cold  -Winds are offshore  -Lies off the coast of N.W Africa  -Dew formation  morning  -Temperature inversion  -Cloudiness/fog/mist","marks":"10","difficulty":"3"},{"id":"theory>Geography>1998>12>a","subject":"Geography","year":"1998","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Give any three reasons why irrigation agriculture is more important in the Nile Basin than in the Niger Basin","images":[],"marking_scheme":"-Higher population in the Nile than in the Niger basin leads to greater demand for food production  -The Nile basin occupies a desert area especially in Egypt. It supplies virtually all water requirements while the Niger areas receive more rainfall  -More intensive use of land on the Nile than on the Niger basin  -Richer alluvial flood plains in the Nile Basin good for agriculture than in the Niger Basin  -Nile basin used more for cash crop production than in the Niger basin","marks":"10","difficulty":"3"},{"id":"theory>Geography>1998>12>b>i","subject":"Geography","year":"1998","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Outline four other uses of the River Nile","images":[],"marking_scheme":"-Domestic and municipal uses  -HEP,generation  -Transportation  -Fishing  -Industrial use  -Tourism and recreation","marks":"5","difficulty":"1"},{"id":"theory>Geography>1998>12>b>ii","subject":"Geography","year":"1998","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"State any four characteristics of the river which limit its usefulness","images":[],"marking_scheme":"-Falls and rapids  -Occasional flooding  -Occurrence of sand spits and bars  -Fluctuation in volumes  -Silting at the mouths  -Occurrence of water weeds  -Load carried in suspension","marks":"5","difficulty":"2"},{"id":"theory>Geography>1998>13>a","subject":"Geography","year":"1998","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"On an outline map of Africa, locate and name:  - the Rivers Nile, Volta and Niger  - one inland and one coal delta  - the Akosombo Dam","images":["data:image/png;base64,"],"marking_scheme":"","marks":"8","difficulty":"3"},{"id":"theory>Geography>1998>13>b","subject":"Geography","year":"1998","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Describe any four uses of the Akosombo Dam","images":[],"marking_scheme":"-HEP generation  -Fishing  -Transportation  -Irrigation  -Industrial use  -Domestic and municipal uses  -Tourism and recreation","marks":"8","difficulty":"2"},{"id":"theory>Geography>1998>13>c","subject":"Geography","year":"1998","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"State three problems facinc hydro-electric power generation in Africa","images":[],"marking_scheme":"-Seasonality of rivers  -Occurrence of sand spits and bars  -Inadequate capital  -Low level of technology  -Inadequate skilled manpower  -Conflict between owner countries","marks":"4","difficulty":"2"},{"id":"theory>Geography>1998>14>a","subject":"Geography","year":"1998","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Write a geographical account of bush fallowing in West Africa under the following heading:    Land preparation","images":[],"marking_scheme":"-Bush clearing/ brushing  -Cleared vegetation cover allowed time to dry  -It is burnt  -Making of mounds or ridges for planting  -Use of cutlasses and hoes","marks":"5","difficulty":"2"},{"id":"theory>Geography>1998>14>b","subject":"Geography","year":"1998","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Write a geographical account of bush fallowing in West Africa under the following heading:    Crops","images":[],"marking_scheme":"-Cereals, e.g maize, millet rice, guinea corn, etc  -Root crops e.g yam, cassava, cocoyam, etc  -Cash crops, e.g cocoa, cotton, groundnut etc  -Berry, e.g tomatoes","marks":"5","difficulty":"2"},{"id":"theory>Geography>1998>14>c","subject":"Geography","year":"1998","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Write a geographical account of bush fallowing in West Africa under the following heading:     Advantages","images":[],"marking_scheme":"-Provision of variety of crops  -Checks erosion as crops are interplanted  -Cheap to operate  -Checks crops disease  -Soil nutrient replenished naturally  -Soil matures for another cropping  -Control of growth of weeds","marks":"5","difficulty":"2"},{"id":"theory>Geography>1998>14>d","subject":"Geography","year":"1998","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Write a geographical account of bush fallowing in West Africa under the following heading:    Disadvantages","images":[],"marking_scheme":"-Wastes a lot of land  -System is labour intensive  -Does not allow for mechanization  -Hastens soil deterioration  -Destruction of economic trees  -Low crop yield  -Farm-holds are small","marks":"5","difficulty":"2"},{"id":"theory>Geography>1998>15>a","subject":"Geography","year":"1998","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"On an outline map of Africa, locate and name:  - the Veldt   - a Mediterranean forest belt   - the tropical grassland belt   - a major town in each of (a)(i) - (iii) above","images":["data:image/png;base64,"],"marking_scheme":"","marks":"8","difficulty":"3"},{"id":"theory>Geography>1998>15>b","subject":"Geography","year":"1998","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Highlight the characteristics of the natural vegetation in any one of the belts shown on your map","images":[],"marking_scheme":"The Veldt:  -Short grasses, less than 1 metre high  -Complete absence of trees except along her valleys or where water table is high  -Warm temperate grassland  -Whither to drab-brown in dry season    (ii) Mediterranean Forest:  -Trees have leathery leaves  -Contains a lot sweet-smelling herbs (Lavender, Rose-Mary, Oleander)  -Low shrubs growing in scattered clumps  -Typical trees include Oak, Laurel, Lavender  -Evergreen or deciduous trees that grow to a height of 2-3 metres in favourable locations  -Trees have long tap-roots  -Needle-like leaves    (iii) Tropical Grassland:  -Trees have long tap-root, thick bark and tiny leaves  -Tall trees and grasses in wetter areas  -Typical trees are isobelina, silk-cotton, acacia, locust bean, shea butter  -Short grasses and short scattered trees are deciduous  -Scrub and thorny bushes towards the driest areas  -Grasses appear green and fresh in the rainy season but turn yellowish during the dry season  -Average height of grass is 2-meters","marks":"8","difficulty":"2"},{"id":"theory>Geography>1998>15>c","subject":"Geography","year":"1998","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Describe the importance of the vegetation chosen in (b) above to man","images":[],"marking_scheme":"Importance of Tropical grassland  to man:  -Provision of wood for cooking  -wood for construction  -raw materials for local crafts  -grasses for building  -grasses for livestock  -provision of herbs for medicinal purposes","marks":"4","difficulty":"2"}];